DROP TABLE IF EXISTS `trorders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `trorders` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `NumarBon` int(11) NOT NULL,
  `Data` date NOT NULL,
  `idFirma` int(11) NOT NULL,
  `DenumireFirma` varchar(255) NOT NULL,
  `Optionale` varchar(255) DEFAULT NULL,
  `Obs` varchar(255) DEFAULT NULL,
  `ValoareFacturata` decimal(10,2) DEFAULT NULL,
  `ComandaClient` int(11) DEFAULT NULL,
  `Finalizata` int(11) DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `Produs` varchar(255) NOT NULL,
  `idCursa` int(11) NOT NULL,
  `DataCursa` date NOT NULL,
  `DenumireCursa` varchar(255) NOT NULL,
  `idRuta` int(11) NOT NULL,
  `DenumireRuta` varchar(255) NOT NULL,
  `idDevco` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=129 DEFAULT CHARSET=latin1;
